    12→function FormField({ field, value, onChange, toolId }) {
    13→  const { t } = useTranslation();
    14→  const label = t(`input.${toolId}.${field.id}.label`, { defaultValue: field.label });
    15→  const placeholder = t(`input.${toolId}.${field.id}.placeholder`, { defaultValue: field.placeholder || '' });
    16→
    17→  const commonProps = {
    18→    id: field.id,
    19→    value: value || '',
    20→    onChange: (e) => onChange(field.id, e.target.value),
    21→    placeholder,
    22→    required: field.required,
    23→  };
    24→
    25→  if (field.type === 'textarea') {
    26→    return (
    27→      <div className="form-group">
    28→        <label className="form-label" htmlFor={field.id}>
    29→          {label}
    30→          {field.required && <span className="required-mark"> *</span>}
    31→        </label>
    32→        <textarea className="form-textarea" rows={4} {...commonProps} />
    33→      </div>
    34→    );
    35→  }
    36→
    37→  if (field.type === 'select') {
    38→    return (
    39→      <div className="form-group">
    40→        <label className="form-label" htmlFor={field.id}>
    41→          {label}
    42→          {field.required && <span className="required-mark"> *</span>}
    43→        </label>
    44→        <select className="form-select" {...commonProps}>
    45→          <option value="">{t('ui.selectOption', { defaultValue: 'Select an option...' })}</option>
    46→          {field.options.map((opt) => (
    47→            <option key={opt} value={opt}>{opt}</option>
    48→          ))}
    49→        </select>
    50→      </div>
    51→    );
    52→  }
    53→
    54→  return (
    55→    <div className="form-group">
    56→      <label className="form-label" htmlFor={field.id}>
    57→        {label}
    58→        {field.required && <span className="required-mark"> *</span>}
    59→      </label>
    60→      <input type="text" className="form-input" {...commonProps} />
    61→    </div>
    62→  );
    63→}
