    65→export default function AIToolInterface({ tool, categoryId }) {
    66→  const [inputs, setInputs] = useState({});
    67→  const [output, setOutput] = useState('');
    68→  const [isStreaming, setIsStreaming] = useState(false);
    69→  const [error, setError] = useState('');
    70→  const [copied, setCopied] = useState(false);
    71→  const [wordCount, setWordCount] = useState(0);
    72→  const outputRef = useRef(null);
    73→  const outputPanelRef = useRef(null);
    74→  const abortRef = useRef(false);
    75→  const finalOutputRef = useRef('');
    76→  const [history, setHistory] = useState([]);
    77→  const [historyOpen, setHistoryOpen] = useState(false);
    78→
    79→  const { currentUser } = useAuth();
    80→  const { canUseTool, trackUsage, isAtLimit, subscription } = useSubscription();
    81→  const { t, i18n } = useTranslation();
    82→
    83→  // Reset when tool changes
    84→  useEffect(() => {
    85→    setInputs({});
    86→    setOutput('');
    87→    setError('');
    88→    setIsStreaming(false);
    89→  }, [tool?.id]);
    90→
    91→  // Load history when tool changes
    92→  useEffect(() => {
    93→    if (tool?.id) {
    94→      try {
    95→        const stored = localStorage.getItem(`gormaran_history_${tool.id}`);
    96→        setHistory(stored ? JSON.parse(stored) : []);
    97→      } catch {
    98→        setHistory([]);
    99→      }
   100→    }
   101→    setHistoryOpen(false);
   102→  }, [tool?.id]);
   103→
   104→  // Track word count
   105→  useEffect(() => {
   106→    if (output) {
   107→      setWordCount(output.split(/\s+/).filter(Boolean).length);
   108→    } else {
   109→      setWordCount(0);
   110→    }
   111→  }, [output]);
   112→
   113→  // Auto-scroll output
   114→  useEffect(() => {
   115→    if (outputRef.current && isStreaming) {
   116→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
   117→    }
   118→  }, [output, isStreaming]);
   119→
   120→  function handleInputChange(fieldId, value) {
   121→    setInputs((prev) => ({ ...prev, [fieldId]: value }));
   122→  }
   123→
   124→  function validateInputs() {
   125→    const required = tool.inputs.filter((f) => f.required);
   126→    for (const field of required) {
   127→      if (!inputs[field.id] || inputs[field.id].trim() === '') {
   128→        const fieldLabel = t(`input.${tool.id}.${field.id}.label`, { defaultValue: field.label });
   129→        return `"${fieldLabel}" is required`;
   130→      }
   131→    }
   132→    return null;
   133→  }
   134→
   135→  async function handleGenerate(e) {
   136→    e.preventDefault();
   137→    setError('');
   138→
   139→    if (!currentUser) {
   140→      setError(t('ui.signInRequired', { defaultValue: 'Please sign in or create a free account to use this tool.' }));
   141→      return;
   142→    }
   143→
   144→    if (!canUseTool(categoryId)) {
   145→      if (isAtLimit()) {
   146→        setError(t('ui.dailyLimitText', { limit: 3, defaultValue: "Daily usage limit reached. Upgrade to Pro for unlimited access." }));
   147→      } else {
   148→        setError(t('ui.proOnlyText', { defaultValue: 'This category is available on Pro and Business plans.' }));
   149→      }
   150→      return;
   151→    }
   152→
   153→    const validationError = validateInputs();
   154→    if (validationError) {
   155→      setError(validationError);
   156→      return;
   157→    }
   158→
   159→    setOutput('');
   160→    finalOutputRef.current = '';
   161→    setIsStreaming(true);
   162→    abortRef.current = false;
   163→    setTimeout(() => outputPanelRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' }), 100);
   164→    const capturedInputs = { ...inputs };
   165→
   166→    await streamAIResponse({
   167→      categoryId,
   168→      toolId: tool.id,
   169→      inputs: { ...inputs, _language: i18n.language },
   170→      onChunk: (text) => {
   171→        if (!abortRef.current) {
   172→          setOutput((prev) => {
   173→            const next = prev + text;
   174→            finalOutputRef.current = next;
   175→            return next;
   176→          });
   177→        }
   178→      },
   179→      onDone: () => {
   180→        setIsStreaming(false);
   181→        trackUsage();
   182→        saveToHistory(capturedInputs, finalOutputRef.current);
   183→      },
   184→      onError: (msg) => {
   185→        setIsStreaming(false);
   186→        setError(msg);
   187→      },
   188→    });
   189→  }
   190→
   191→  function handleStop() {
   192→    abortRef.current = true;
   193→    setIsStreaming(false);
   194→  }
   195→
   196→  async function handleCopy() {
   197→    if (!output) return;
   198→    await navigator.clipboard.writeText(output);
   199→    setCopied(true);
   200→    setTimeout(() => setCopied(false), 2000);
   201→  }
   202→
   203→  function handleClear() {
   204→    setOutput('');
   205→    setError('');
   206→    setInputs({});
   207→    finalOutputRef.current = '';
   208→  }
   209→
   210→  function saveToHistory(queryInputs, queryOutput) {
   211→    if (!tool?.id || !queryOutput) return;
   212→    const entry = { id: Date.now(), timestamp: new Date().toISOString(), inputs: queryInputs, output: queryOutput };
   213→    const key = `gormaran_history_${tool.id}`;
   214→    const existing = (() => { try { return JSON.parse(localStorage.getItem(key) || '[]'); } catch { return []; } })();
   215→    const updated = [entry, ...existing].slice(0, 10);
   216→    localStorage.setItem(key, JSON.stringify(updated));
   217→    setHistory(updated);
   218→  }
   219→
   220→  const locked = !canUseTool(categoryId) && !isAtLimit();
   221→  const atLimit = isAtLimit() && subscription === 'free';
   222→
   223→  if (!tool) {
   224→    return (
   225→      <div className="ai-tool__empty">
   226→        <div className="ai-tool__empty-icon">⬅️</div>
   227→        <h3>{t('ui.selectTool', { defaultValue: 'Select a tool to get started' })}</h3>
   228→        <p>{t('ui.selectToolSub', { defaultValue: 'Choose a tool from the sidebar to generate AI-powered content' })}</p>
   229→      </div>
   230→    );
   231→  }
   232→
   233→  const toolName = t(`tool.${tool.id}.name`, { defaultValue: tool.name });
   234→  const toolDesc = t(`tool.${tool.id}.desc`, { defaultValue: tool.description });
   235→
   236→  return (
   237→    <div className="ai-tool">
   238→      {/* Header */}
   239→      <div className="ai-tool__header">
   240→        <div className="ai-tool__title-row">
   241→          <span className="ai-tool__icon">{tool.icon}</span>
   242→          <div>
   243→            <h2 className="ai-tool__title">{toolName}</h2>
   244→            <p className="ai-tool__description">{toolDesc}</p>
   245→          </div>
   246→        </div>
   247→      </div>
   248→
   249→      {/* Upgrade notice */}
   250→      {(locked || atLimit) && (
   251→        <div className="ai-tool__upgrade">
   252→          <div className="ai-tool__upgrade-icon">🔒</div>
   253→          <div>
