    15→/* ── SVG Sparkline Chart ─────────────────────────────────────────── */
    16→function FollowerChart({ months, counts, t }) {
    17→  const W = 320, H = 90;
    18→  const PAD = { top: 12, right: 8, bottom: 24, left: 8 };
    19→  const vals = counts.map((v, i) => ({ v: Number(v), i })).filter((x) => counts[x.i] !== '');
    20→
    21→  if (vals.length < 2) return null;
    22→
    23→  const numbers = vals.map((x) => x.v);
    24→  const min = Math.min(...numbers);
    25→  const max = Math.max(...numbers);
    26→  const range = max - min || 1;
    27→  const innerW = W - PAD.left - PAD.right;
    28→  const innerH = H - PAD.top - PAD.bottom;
    29→
    30→  const pts = vals.map((x) => ({
    31→    x: PAD.left + (x.i / (months.length - 1)) * innerW,
    32→    y: PAD.top + (1 - (x.v - min) / range) * innerH,
    33→    v: x.v,
    34→    i: x.i,
    35→  }));
    36→
    37→  /* Smooth cubic bezier */
    38→  let linePath = `M ${pts[0].x} ${pts[0].y}`;
    39→  for (let k = 1; k < pts.length; k++) {
    40→    const prev = pts[k - 1];
    41→    const curr = pts[k];
    42→    const cp = (curr.x - prev.x) / 2;
    43→    linePath += ` C ${prev.x + cp} ${prev.y}, ${curr.x - cp} ${curr.y}, ${curr.x} ${curr.y}`;
    44→  }
    45→  const areaPath = `${linePath} L ${pts[pts.length - 1].x} ${H - PAD.bottom} L ${pts[0].x} ${H - PAD.bottom} Z`;
    46→
    47→  const pct = pts[0].v > 0 ? Math.round(((pts[pts.length - 1].v - pts[0].v) / pts[0].v) * 100) : 0;
    48→
    49→  return (
    50→    <div className="ig-chart">
    51→      <div className="ig-chart__meta">
    52→        <span className="ig-chart__label">{t('ig.chart.growth', { defaultValue: 'Follower growth' })}</span>
    53→        <span className={`ig-chart__pct ${pct >= 0 ? 'pos' : 'neg'}`}>
    54→          {pct >= 0 ? '+' : ''}{pct}%
    55→        </span>
    56→      </div>
    57→      <svg viewBox={`0 0 ${W} ${H}`} className="ig-chart__svg" aria-hidden="true">
    58→        <defs>
    59→          <linearGradient id="igAreaGrad" x1="0" y1="0" x2="0" y2="1">
    60→            <stop offset="0%" stopColor="#e1306c" stopOpacity="0.2" />
    61→            <stop offset="100%" stopColor="#833ab4" stopOpacity="0" />
    62→          </linearGradient>
    63→          <linearGradient id="igLineGrad" x1="0" y1="0" x2="1" y2="0">
    64→            <stop offset="0%" stopColor="#e1306c" />
    65→            <stop offset="100%" stopColor="#833ab4" />
    66→          </linearGradient>
    67→        </defs>
    68→        <path d={areaPath} fill="url(#igAreaGrad)" />
    69→        <path d={linePath} fill="none" stroke="url(#igLineGrad)" strokeWidth="2.5" strokeLinecap="round" />
    70→        {pts.map((p) => (
    71→          <g key={p.i}>
    72→            <circle cx={p.x} cy={p.y} r="3.5" fill="#e1306c" />
    73→            <text x={p.x} y={H - PAD.bottom + 14} textAnchor="middle" fontSize="8" fill="var(--text-muted)">
    74→              {months[p.i]}
    75→            </text>
    76→          </g>
    77→        ))}
    78→      </svg>
    79→    </div>
    80→  );
    81→}
