### 3. SUBSCRIPTION GATING LOGIC

**Location: `/Users/gabiorma/gormaran-ai-growth-hub/src/context/SubscriptionContext.js`**

**Subscription Plans:**
```javascript
const PLANS = {
  free: {
    name: 'Free',
    dailyLimit: 3,
    categories: ['marketing', 'content'],
  },
  pro: {
    name: 'Pro',
    dailyLimit: Infinity,
    categories: ['marketing', 'content', 'strategy', 'digital'],
  },
  business: {
    name: 'Business',
    dailyLimit: Infinity,
    categories: ['marketing', 'content', 'strategy', 'digital', 'ecommerce', 'agency', 'startup'],
  },
  admin: {
    name: 'Admin',
    dailyLimit: Infinity,
    categories: ['marketing', 'content', 'strategy', 'digital', 'ecommerce', 'agency', 'startup', 'automation'],
  },
};
```

**Key gating functions (lines 51-85):**

```javascript
function canUseTool(categoryId) {
  if (!currentUser) return false;                    // Must be logged in
  if (subscription === 'admin') return true;         // Admin bypasses all
  const plan = PLANS[subscription] || PLANS.free;
  if (!plan.categories.includes(categoryId)) return false; // Check plan access
  if (plan.dailyLimit !== Infinity && usageCount >= plan.dailyLimit) return false; // Check daily limit
  return true;
}

function isCategoryLocked(categoryId) {
  if (subscription === 'admin') return false;
  const plan = PLANS[subscription] || PLANS.free;
  return !plan.categories.includes(categoryId);  // True if category not in plan
}

function isAtLimit() {
  if (subscription === 'admin') return false;
  const plan = PLANS[subscription] || PLANS.free;
  return plan.dailyLimit !== Infinity && usageCount >= plan.dailyLimit;
}
```

**Access Logic:**
- Free users: 3 daily requests, can use 'marketing' & 'content' categories only
- Pro users: Unlimited daily requests, access to marketing, content, strategy, digital
- Business users: Unlimited daily requests, access to all except 'automation' (add-on)
- Admin users: Unlimited access to everything

